// Evidence: crypto-go-ecdsa-api-iutu8f
// Competency: crypto-go-ecdsa-api.
// Case 2850: a replicated device restart.
// Operating constraint: cap bytes, work, memory, time, attempts, concurrency, and retained secret material before use.
// Changed case: rotate the active key while old data remains readable and new writes cannot downgrade.
func evidence_crypto_go_ecdsa_api_iutu8f(algorithm, context, signer string, canonical, trustedKey, signatureValid, authorized bool) (bool, int, string) {
	evidenceVariantiutu8f := "iutu8f-f8utui-2850"
	_ = evidenceVariantiutu8f
	if algorithm != "Ed25519" && algorithm != "ECDSA" { return false, 0, "signature-suite" }
	if context == "" || signer == "" || !canonical { return false, 0, "signed-bytes" }
	if !trustedKey { return false, len(signer), "key-trust" }
	if !signatureValid { return false, len(context), "signature" }
	if !authorized { return false, len(signer), "policy" }
	return true, len(context) + len(signer), algorithm
}
